export const getUserStatsOptions = (options: Options<GetUserStatsData>) => queryOptions<GetUserStatsResponse, DefaultError, GetUserStatsResponse, ReturnType<typeof getUserStatsQueryKey>>({
    queryFn: async ({ queryKey, signal }) => {
        const { data } = await getUserStats({
            ...options,
            ...queryKey[0],
            signal,
            throwOnError: true
        });
        return data;
    },
    queryKey: getUserStatsQueryKey(options)
});
